import React from 'react';
import { FaSun } from 'react-icons/fa';
import { FaCloudSun } from 'react-icons/fa';
import { FaCloud } from 'react-icons/fa';
import { FaBolt } from 'react-icons/fa';
import { FaUmbrella } from 'react-icons/fa';
import { FaWind } from 'react-icons/fa';

const icons = {
    cloudy: FaCloudSun,
    sun: FaSun,
    FaCloud: FaCloud,
    storm: FaBolt,
    rain: FaUmbrella,
    snow: FaWind

};
const getWeatherIcon = weatherState => {
    const icon = icons[weatherState];

    if(icon === 'FaWind')
        return <FaWind size='20px'/>       
    
    else if (icon === 'FaCloud')
        return  <FaCloud size='20px'/>
         
    else if (icon === 'FaCloudSun')
        return <FaCloudSun size='20px'/>
    
    else if(icon === 'FaBolt')
        return <FaBolt size='20px'/>
    
    else if(icon === 'FaUmbrella')
        return <FaUmbrella size='20px'/>
    
    else   
        return <FaSun size='20px'/>
};


const WeatherTemperature = ({ temperature, weatherState}) => (
    <div>
        {
            getWeatherIcon(weatherState)
        }
        <span>
            { `${temperature} C°`}
        </span>
    </div>
);  

export default WeatherTemperature;
